// API Key authentication check - timing-safe comparison
const headers = $input.first().json.headers || {};

// Case-insensitive header lookup (defense against platform normalization changes)
const headerKeys = Object.keys(headers);
const apiKeyHeader = headerKeys.find(k => k.toLowerCase() === 'x-api-key');
const providedKeyRaw = apiKeyHeader !== undefined ? headers[apiKeyHeader] : '';
const expectedKeyRaw = $env.WHISPER_API_KEY;

// Limit key length to prevent DoS via multi-megabyte payloads
const MAX_KEY_LENGTH = 256;
const providedKey = typeof providedKeyRaw === 'string' ? providedKeyRaw.slice(0, MAX_KEY_LENGTH) : '';
const expectedKey = typeof expectedKeyRaw === 'string' ? expectedKeyRaw.slice(0, MAX_KEY_LENGTH) : '';

// Timing-safe comparison - prevents timing attacks on API key
function timingSafeEqual(a, b) {
  if (typeof a !== 'string' || typeof b !== 'string') return false;
  const MAX_LEN = 256;
  if (a.length > MAX_LEN || b.length > MAX_LEN) return false;

  let result = 0;
  // Constant-time comparison: always iterate MAX_LEN, use 0 for out-of-bounds
  for (let i = 0; i < MAX_LEN; i++) {
    const charA = i < a.length ? a.charCodeAt(i) : 0;
    const charB = i < b.length ? b.charCodeAt(i) : 0;
    result |= charA ^ charB;
  }
  // Include length check in constant-time result
  result |= (a.length === b.length) ? 0 : 1;
  return result === 0;
}

if (expectedKey && !timingSafeEqual(providedKey, expectedKey)) {
  return [{ json: { valid: false, error: 'Authentication failed' } }];
}

// Get input parameters
const audio = $input.first().json.audio;
const audioPath = ($input.first().json.audio_path || '').trim();
const language = ($input.first().json.language || 'en').toLowerCase();
const model = ($input.first().json.model || 'base').toLowerCase();
const responseFormat = ($input.first().json.response_format || 'json').toLowerCase();

// Audio size validation (DoS protection: ~2MB base64 ≈ 1.5MB binary)
if (audio && audio.length > 2097152) {
  return [{ json: { valid: false, error: 'Audio too large: max ~2MB base64 encoded' } }];
}

// Valid language codes
const validLanguages = [
  'en', 'es', 'fr', 'de', 'it', 'pt', 'nl', 'ja', 'zh', 'ko', 'ar', 'hi', 'pl', 'ru', 'tr'
];

// Valid model names
const validModels = [
  'tiny', 'base', 'small', 'medium', 'large', 'large-v1', 'large-v2', 'large-v3',
  'distil-small-en', 'distil-medium-en'
];

// Valid response formats
const validResponseFormats = ['json', 'text', 'srt', 'vtt', 'verbose_json'];

// ENHANCED Path traversal detection (blocks: ../, ..\, %2e%2e, %252e%252e, null bytes, absolute paths, Windows drive letters)
// Note: Use \\u0000 in JSON to get \u0000 in JS regex for null byte detection
const pathTraversalPattern = /(\.\.[/\\]|%2e%2e[/\\]|%252e%252e|%00|\\u0000|^\/|^[a-zA-Z]:\\)/i;

// Validate required fields
if (!audio && !audioPath) {
  return [{ json: { valid: false, error: 'Either audio (base64) or audio_path is required' } }];
}

// Validate language
if (!validLanguages.includes(language)) {
  return [{ json: { valid: false, error: 'Invalid language. Must be one of: ' + validLanguages.join(', ') } }];
}

// Validate model
if (!validModels.includes(model)) {
  return [{ json: { valid: false, error: 'Invalid model. Must be one of: ' + validModels.join(', ') } }];
}

// Validate response format
if (!validResponseFormats.includes(responseFormat)) {
  return [{ json: { valid: false, error: 'Invalid response_format. Must be one of: ' + validResponseFormats.join(', ') } }];
}

// Path traversal protection on audio_path
if (audioPath) {
  // Decode and normalize for Unicode NFC attack detection
  let normalizedPath;
  try {
    normalizedPath = decodeURIComponent(audioPath).normalize('NFC');
  } catch (e) {
    return [{ json: { valid: false, error: 'Invalid audio_path: malformed URL encoding' } }];
  }

  if (pathTraversalPattern.test(audioPath) || pathTraversalPattern.test(normalizedPath)) {
    return [{ json: { valid: false, error: 'Invalid audio_path: path traversal detected' } }];
  }
}

return [{
  json: {
    valid: true,
    audio: audio,
    audio_path: audioPath,
    language: language,
    model: model,
    response_format: responseFormat
  }
}];

// Prepare audio for Whisper STT service
// - If audio_path is provided, read the file and convert to base64
// - If audio (base64) is provided, pass it through with binary data

const audioPath = $('Validate Input').item.json.audio_path;
const audioBase64 = $('Validate Input').item.json.audio;
const language = $('Validate Input').item.json.language;
const model = $('Validate Input').item.json.model;
const responseFormat = $('Validate Input').item.json.response_format;

if (audioPath) {
  // Read file from filesystem and convert to base64
  const fs = require('fs');
  const filePath = audioPath;

  if (!fs.existsSync(filePath)) {
    return [{ json: { valid: false, error: 'Audio file not found: ' + filePath } }];
  }

  const fileBuffer = fs.readFileSync(filePath);
  const base64Data = fileBuffer.toString('base64');

  return [{
    json: {
      valid: true,
      audio: base64Data,
      audio_path: audioPath,
      language: language,
      model: model,
      response_format: responseFormat
    },
    binary: {
      audio: {
        data: base64Data,
        mimeType: 'audio/mpeg'
      }
    }
  }];
}

// Base64 audio provided - pass through with binary data
return [{
  json: {
    valid: true,
    audio: audioBase64,
    audio_path: audioPath,
    language: language,
    model: model,
    response_format: responseFormat
  },
  binary: {
    audio: {
      data: audioBase64,
      mimeType: 'audio/mpeg'
    }
  }
}];
